### State Definitions
```rust
#[derive(Debug, Clone)]
pub enum CircuitState {
    /// Normal operation - worker accepts requests
    Closed,
    /// Circuit tripped - worker excluded from selection
    Open {
        tripped_at: Instant,
        failure_count: u32,
        next_probe_at: Instant,
    },
    /// Testing recovery - single probe request allowed
    HalfOpen {
        entered_at: Instant,
    },
}
```

### Configuration
```rust
pub struct CircuitBreakerConfig {
    /// Failures before tripping circuit
    failure_threshold: u32,        // default: 3
    /// Initial cooldown before half-open
    initial_cooldown: Duration,    // default: 30s
    /// Max cooldown (exponential backoff cap)
    max_cooldown: Duration,        // default: 5min
    /// Backoff multiplier
    backoff_multiplier: f64,       // default: 2.0
    /// Successes needed to close circuit
    success_threshold: u32,        // default: 1
}
```

### Health Check Integration
```rust
async fn check_worker_with_circuit(
    worker: &WorkerState,
    circuit: &mut CircuitState,
    config: &CircuitBreakerConfig,
) -> HealthCheckResult {
    match circuit {
        CircuitState::Closed => {
            // Normal health check
            let result = check_worker_health(worker).await;
            if !result.healthy {
                // Track failure, possibly trip
            }
            result
        }
        CircuitState::Open { next_probe_at, .. } => {
            if Instant::now() >= *next_probe_at {
                // Transition to half-open
                *circuit = CircuitState::HalfOpen { entered_at: Instant::now() };
                // Fall through to probe
            } else {
                // Skip check, circuit still open
                return HealthCheckResult::skipped();
            }
        }
        CircuitState::HalfOpen { .. } => {
            // Probe check
            let result = check_worker_health(worker).await;
            if result.healthy {
                *circuit = CircuitState::Closed;
            } else {
                // Re-trip with increased backoff
                *circuit = CircuitState::Open { /* ... */ };
            }
            result
        }
    }
}
```

